import { BarChart } from '@tale-ui/charts/bar-chart';

const data = [
  { quarter: 'Q1', sales: 12000, profit: 3200 },
  { quarter: 'Q2', sales: 15000, profit: 4100 },
  { quarter: 'Q3', sales: 18000, profit: 5600 },
  { quarter: 'Q4', sales: 22000, profit: 7800 },
];

export function Example() {
  return (
    <BarChart.Root data={data} width={600} height={300}>
      <BarChart.Grid strokeDasharray="3 3" />
      <BarChart.XAxis dataKey="quarter" />
      <BarChart.YAxis />
      <BarChart.Tooltip />
      <BarChart.Legend />
      <BarChart.Bar dataKey="sales" />
      <BarChart.Bar dataKey="profit" />
    </BarChart.Root>
  );
}
